import React, { useMemo } from "react";
import { Polygon, Polyline } from "react-leaflet";

function toRadians(degrees) {
  return (degrees * Math.PI) / 180;
}

function toDegrees(radians) {
  return (radians * 180) / Math.PI;
}

function normalizeLongitude(longitude) {
  let value = longitude;

  while (value > 180) {
    value -= 360;
  }
  while (value < -180) {
    value += 360;
  }

  return value;
}

function getSunCoordinates(date) {
  const julianDate = date.getTime() / 86400000 + 2440587.5;
  const centuries = (julianDate - 2451545.0) / 36525.0;

  const meanLongitude =
    (280.46646 + centuries * (36000.76983 + centuries * 0.0003032)) % 360;
  const meanAnomaly =
    357.52911 + centuries * (35999.05029 - 0.0001537 * centuries);

  const equationOfCenter =
    Math.sin(toRadians(meanAnomaly)) *
      (1.914602 - centuries * (0.004817 + 0.000014 * centuries)) +
    Math.sin(toRadians(2 * meanAnomaly)) * (0.019993 - 0.000101 * centuries) +
    Math.sin(toRadians(3 * meanAnomaly)) * 0.000289;

  const trueLongitude = meanLongitude + equationOfCenter;
  const obliquity = 23.439291 - 0.0130042 * centuries;

  const lambdaRad = toRadians(trueLongitude);
  const obliquityRad = toRadians(obliquity);

  const declinationRad = Math.asin(Math.sin(obliquityRad) * Math.sin(lambdaRad));
  const rightAscensionRad = Math.atan2(
    Math.cos(obliquityRad) * Math.sin(lambdaRad),
    Math.cos(lambdaRad)
  );

  const gmst =
    280.46061837 +
    360.98564736629 * (julianDate - 2451545.0) +
    centuries * centuries * (0.000387933 - centuries / 38710000);

  const subsolarLongitude = normalizeLongitude(toDegrees(rightAscensionRad) - gmst);

  return {
    declinationDeg: toDegrees(declinationRad),
    declinationRad,
    subsolarLongitude,
  };
}

function buildTerminator(subsolarLongitude, declinationRad) {
  const points = [];

  // Solar terminator: tan(phi) = -cos(H) / tan(delta)
  // where phi is latitude and H is local hour angle.
  for (let longitude = -180; longitude <= 180; longitude += 2) {
    const hourAngle = toRadians(normalizeLongitude(longitude - subsolarLongitude));
    const latitude = toDegrees(Math.atan2(-Math.cos(hourAngle), Math.tan(declinationRad)));
    points.push([latitude, longitude]);
  }

  return points;
}

function pointInPolygon(point, polygon) {
  const x = point[1];
  const y = point[0];
  let inside = false;

  for (let i = 0, j = polygon.length - 1; i < polygon.length; j = i, i += 1) {
    const xi = polygon[i][1];
    const yi = polygon[i][0];
    const xj = polygon[j][1];
    const yj = polygon[j][0];

    const intersect =
      yi > y !== yj > y && x < ((xj - xi) * (y - yi)) / (yj - yi + Number.EPSILON) + xi;

    if (intersect) {
      inside = !inside;
    }
  }

  return inside;
}

function buildNightPolygon(terminator, antiSolar) {
  const southCap = [...terminator, [-90, 180], [-90, -180]];
  const northCap = [...terminator, [90, 180], [90, -180]];

  return pointInPolygon(antiSolar, southCap) ? southCap : northCap;
}

function shiftLongitudes(points, shift) {
  return points.map(([latitude, longitude]) => [latitude, longitude + shift]);
}

export default function DayNightOverlay() {
  const now = Date.now();

  const { wrappedPolygons, wrappedTerminators } = useMemo(() => {
    const sun = getSunCoordinates(new Date(now));
    const antiSolar = [
      -sun.declinationDeg,
      normalizeLongitude(sun.subsolarLongitude + 180),
    ];

    const terminator = buildTerminator(sun.subsolarLongitude, sun.declinationRad);
    const nightPolygon = buildNightPolygon(terminator, antiSolar);

    const shifts = [-360, 0, 360];

    return {
      wrappedPolygons: shifts.map((shift) => shiftLongitudes(nightPolygon, shift)),
      wrappedTerminators: shifts.map((shift) => shiftLongitudes(terminator, shift)),
    };
  }, [now]);

  return (
    <>
      {wrappedPolygons.map((polygon, index) => (
        <Polygon
          key={`night-${index}`}
          positions={polygon}
          pathOptions={{
            color: "#00143a",
            fillColor: "#00143a",
            fillOpacity: 0.5,
            opacity: 0,
            weight: 0,
            smoothFactor: 1,
          }}
        />
      ))}
      {wrappedTerminators.map((line, index) => (
        <Polyline
          key={`terminator-${index}`}
          positions={line}
          pathOptions={{
            color: "#7aa2ff",
            opacity: 0.22,
            weight: 1.2,
          }}
        />
      ))}
    </>
  );
}
